package ingest

import (
	"testing"
)

func TestExtractFrontMatter(t *testing.T) {
	input := `---
title: "Test Document"
kind: decision
date: 2026-02-22
tags: [embedding, model]
status: active
supersedes: DEC-007
scope: global
---

## First Section

Content here.`

	fm, body := ExtractFrontMatter(input)

	if fm.Title != "Test Document" {
		t.Errorf("title = %q, want %q", fm.Title, "Test Document")
	}
	if fm.Kind != "decision" {
		t.Errorf("kind = %q, want %q", fm.Kind, "decision")
	}
	if fm.Date != "2026-02-22" {
		t.Errorf("date = %q, want %q", fm.Date, "2026-02-22")
	}
	if len(fm.Tags) != 2 || fm.Tags[0] != "embedding" || fm.Tags[1] != "model" {
		t.Errorf("tags = %v, want [embedding, model]", fm.Tags)
	}
	if fm.Status != "active" {
		t.Errorf("status = %q, want %q", fm.Status, "active")
	}
	if fm.Supersedes != "DEC-007" {
		t.Errorf("supersedes = %q, want %q", fm.Supersedes, "DEC-007")
	}
	if fm.Scope != "global" {
		t.Errorf("scope = %q, want %q", fm.Scope, "global")
	}
	if !containsString(body, "## First Section") {
		t.Errorf("body should contain section header, got: %s", body[:min(100, len(body))])
	}
}

func TestExtractFrontMatterNoFrontMatter(t *testing.T) {
	input := `## First Section

No front matter here.`

	fm, body := ExtractFrontMatter(input)
	if fm.Title != "" {
		t.Errorf("title should be empty, got %q", fm.Title)
	}
	if body != input {
		t.Error("body should be the full input when no front matter")
	}
}

func TestExtractFrontMatterMissingClosing(t *testing.T) {
	input := `---
title: "Incomplete"
kind: reference

## Content without closing delimiter`

	fm, body := ExtractFrontMatter(input)
	if fm.Title != "" {
		t.Errorf("title should be empty for unclosed front matter, got %q", fm.Title)
	}
	if body != input {
		t.Error("body should be full input for unclosed front matter")
	}
}

func TestExtractFrontMatterEmpty(t *testing.T) {
	input := `---
---

## Content`

	fm, body := ExtractFrontMatter(input)
	if fm.Title != "" {
		t.Errorf("title should be empty for empty front matter, got %q", fm.Title)
	}
	if !containsString(body, "## Content") {
		t.Error("body should contain content after empty front matter")
	}
}

func TestExtractFrontMatterRawFields(t *testing.T) {
	input := `---
title: "Test"
custom_field: "custom_value"
---

Body`

	fm, _ := ExtractFrontMatter(input)
	if fm.Raw == nil {
		t.Fatal("Raw should not be nil")
	}
	if fm.Raw["custom_field"] != "custom_value" {
		t.Errorf("custom_field = %v, want %q", fm.Raw["custom_field"], "custom_value")
	}
}

func containsString(s, substr string) bool {
	return len(s) >= len(substr) && (s == substr || len(s) > 0 && findSubstring(s, substr))
}

func findSubstring(s, substr string) bool {
	for i := 0; i <= len(s)-len(substr); i++ {
		if s[i:i+len(substr)] == substr {
			return true
		}
	}
	return false
}
